import { request } from '../axios';
import { connectToApp } from '../common/connect-to-app';
import { getRedirectUri } from '../utils/url-utils';
import { isCookieSet, isRedirectedTo } from '../utils/workflow-utils';
import { fixAcrValues } from './fix-acr-values';
import { getNetIQEnv } from './get-netiq-env';
import { netIQLogin } from './netiq-login';
import log from 'loglevel';

export async function appNetIQAuthenticationWorkflow(
  startUrl: string,
  username: string,
  password: string,
  response?: any,
) {
  log.info(`* Authenticating with '${username}' for '${startUrl}' using NetIQ`);

  let expectedCookie: string;

  // ----------------------------------------
  // Connect to application
  // ----------------------------------------

  // We may have already connected to the app to identify the type of IDP we are dealing with
  if (!response) response = await connectToApp(startUrl);

  expectedCookie = 'mod_auth_openidc_state_';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected application to set '${expectedCookie}' cookie.`);

  // Identify the NetIQ environment and URLs
  const netIQEnv = getNetIQEnv(response.headers.location);
  const idpAuthzURL = `https://${netIQEnv}/nidp/oauth/nam/authz`;
  const idpLoginURL = `https://${netIQEnv}/nidp//app/login`;

  if (!isRedirectedTo(idpAuthzURL, response))
    throw new Error(`Expected application to redirect to ${idpAuthzURL}`);

  // Extract redirect_uri for later redirection check
  const redirect_uri = getRedirectUri(response.headers.location);

  // ----------------------------------------
  // Connect to idp authz
  // ----------------------------------------

  // Set acr_values=secure/name/password/uri to bypass certificate request.
  // This magick trick only seems to work with idp2, not with idp.
  let authzUrl: string = fixAcrValues(response.headers.location);
  response = await request({ method: 'GET', url: authzUrl });

  expectedCookie = 'JSESSIONID';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected idp authz to set '${expectedCookie}' cookie.`);

  if (!isRedirectedTo(idpLoginURL, response))
    throw new Error(`Expected idp authz to redirect to ${idpLoginURL}`);

  // ----------------------------------------
  // Open idp login page
  // ----------------------------------------

  response = await request({ method: 'GET', url: response.headers.location });

  if (response.status != 200)
    throw new Error('Expected idp login page to be successfully displayed.');

  // ----------------------------------------
  // Log in to idp
  // ----------------------------------------

  response = await netIQLogin(idpLoginURL, username, password);

  if (response.status != 200)
    throw new Error('Expected idp login to be successful.');

  expectedCookie = 'JSESSIONID';
  if (!isCookieSet(expectedCookie, response)) {
    const msg = `idp did not set '${expectedCookie}' cookie. This usually means your credentials are not valid.`;
    throw new Error(msg);
  }

  // ----------------------------------------
  // Go back to idp authz
  // ----------------------------------------

  authzUrl += '&resourceServer=IdentityProvider';
  response = await request({ method: 'GET', url: authzUrl });

  expectedCookie = '_PA_SDK_SSO_';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected idp authz to set '${expectedCookie}' cookie.`);

  if (!isRedirectedTo(redirect_uri, response))
    throw new Error(`Expected idp authz to redirect to ${redirect_uri}`);

  // ----------------------------------------
  // Open app oidc
  // ----------------------------------------

  response = await request({ method: 'GET', url: response.headers.location });

  expectedCookie = 'mod_auth_openidc_state_';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected app oidc to set '${expectedCookie}' cookie.`);

  expectedCookie = 'mod_auth_openidc_session';
  if (!isCookieSet(expectedCookie, response))
    throw new Error(`Expected app oidc to set '${expectedCookie}' cookie.`);

  if (!isRedirectedTo(startUrl, response))
    throw new Error(`Expected app oidc to redirect to ${startUrl}`);
}
